description:
Implement SigMeta and SigFieldMeta - the metadata structures that boring templates iterate over.

Location: crates/dspy-rs/src/signature/compiled.rs (new file) or dspy-rs/src/prompt/compiled_signature.rs

```rust
/// Metadata about a single field (input or output)
#[derive(Debug, Clone, serde::Serialize)]
pub struct SigFieldMeta {
    /// Name as seen by LLM (rendered name)
    pub llm_name: &'static str,
    /// Rust field name (for lookup in inputs map)
    pub rust_name: &'static str,
    /// Simplified type name for prompt (e.g., "list[Document]")
    pub type_name: String,
    /// Schema string for output fields (JSON/YAML format description)
    pub schema: Option<String>,
}

/// Metadata about a signature for prompt templates
#[derive(Debug, Clone, serde::Serialize)]
pub struct SigMeta {
    pub inputs: Vec<SigFieldMeta>,
    pub outputs: Vec<SigFieldMeta>,
}

impl SigMeta {
    /// Build from a Signature type's metadata
    pub fn from_signature<S: Signature>() -> Self {
        let inputs = S::Input::fields()
            .iter()
            .map(|f| SigFieldMeta {
                llm_name: f.name,
                rust_name: f.rust_name,
                type_name: simplify_type_name(&(f.type_ir)()),
                schema: None,  // Input fields don't need schema
            })
            .collect();

        let outputs = S::Output::fields()
            .iter()
            .map(|f| {
                let ty = (f.type_ir)();
                SigFieldMeta {
                    llm_name: f.name,
                    rust_name: f.rust_name,
                    type_name: simplify_type_name(&ty),
                    schema: Some(build_field_schema(&ty)),
                }
            })
            .collect();

        Self { inputs, outputs }
    }
}

fn simplify_type_name(ty: &TypeIR) -> String {
    // Convert TypeIR to human-readable: "list[Document]", "string", etc.
    ty.diagnostic_repr().to_string()
}

